class LoggerMetrics(object):
    def __init__(self,
                 *args,
                 operation_type:str = "OPERATION_TYPE",
                 matrix_id:str      = "MATRIX",
                 worker_id:str      = "WORKER_ID",
                 algorithm:str      = "ALGORITHM",
                 arrival_time:int   = 0, 
                 end_time:int       = 0, 
                 service_time:int   = 0,
                 latency:int        = 0,
                 k_value:int        = 0,
                 m_value:int        = 0,
                 n_iterations:int   = 0,
                 **kwargs,

                 
                 
                 ):
        self.operation_type = operation_type
        self.matrix_id      = matrix_id
        self.worker_id      = worker_id
        self.algorithm      = algorithm 
        self.arrival_time   = arrival_time
        self.end_time       = end_time
        self.service_time   = service_time
        self.latency        = latency
        self.k_value        = k_value
        self.m_value        = m_value
        self.n_iterations   = n_iterations
        self.args           = args
        self.kwargs         = kwargs
    def __str__(self):
        value:str = "{},{},{},{},{},{},{},{},{},{},{}".format(
            self.operation_type,
            self.matrix_id,
            self.worker_id,
            self.algorithm,
            self.arrival_time, 
            self.end_time, 
            self.service_time,
            self.latency,
            self.k_value,
            self.m_value,
            self.n_iterations
            )
        # value   = ""
        y       = ",".join(self.args)
        value_y = value if len(self.args) == 0 else "{},{}".format(value,y)
        values  = list(map(str,self.kwargs.values()))
        x       = ",".join(values)
        value_x = value if len(values) == 0 else "{},{}".format(value_y,x)
        return value_x
        # return value   
        
    

if __name__ == "__main__":
    lm = LoggerMetrics(operation_type="ENCRYPT",arrival_time=0, end_time=0, service_time=1,test="AL_ULTIMO_KWARGS")